"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([["21295"],{424180(e){e.exports=JSON.parse('{"tag":{"label":"structure","permalink":"/dst-api-webdocs/docs/tags/structure","allTagsPath":"/dst-api-webdocs/docs/tags","count":142,"items":[{"id":"game-scripts/prefabs/altar_prototyper","title":"Altar Prototyper","description":"Implements a reusable crafting station with dynamic lighting and state-dependent behavior (intact or broken), supporting research tree activation, repair, and combat-triggered creature spawns.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/altar_prototyper"},{"id":"game-scripts/prefabs/anchor","title":"Anchor","description":"A deployable boat accessory that prevents vessel movement and interacts with water physics and environmental systems.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/anchor"},{"id":"game-scripts/prefabs/archive_resonator","title":"Archive Resonator","description":"A deployable device that scans for moon relics or alien artifacts to retrieve and consumes uses upon successful scanning or idle operation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/archive_resonator"},{"id":"game-scripts/components/archivemanager","title":"Archivemanager","description":"Manages the power state of the Archive structure and synchronizes world state tags.","permalink":"/dst-api-webdocs/docs/game-scripts/components/archivemanager"},{"id":"game-scripts/prefabs/arrowsign","title":"Arrowsign","description":"Implements the directional sign post and panel prefabs for placement and interaction in the game world, supporting construction, writing, destruction, and orientation persistence.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/arrowsign"},{"id":"game-scripts/prefabs/beebox","title":"Beebox","description":"Defines the Beebox structure entity which produces honey and spawns bees based on season and light conditions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/beebox"},{"id":"game-scripts/prefabs/beefalo_groomer","title":"Beefalo Groomer","description":"A structure prefab that allows players to groom and dress beefalos with custom skins and clothing.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/beefalo_groomer"},{"id":"game-scripts/prefabs/beehive","title":"Beehive","description":"Defines the Beehive prefab entity that spawns bees, handles combat interactions, and drops loot when destroyed.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/beehive"},{"id":"game-scripts/prefabs/boat_magnet","title":"Boat Magnet","description":"A deployable structure component that enables boat magnet functionality by pairing with a beacon and responding to beacon state changes via the state graph.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boat_magnet"},{"id":"game-scripts/prefabs/boat_magnet_beacon","title":"Boat Magnet Beacon","description":"Manages the beacon that pairs with a boat magnet to control magnet movement when placed on a boat.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boat_magnet_beacon"},{"id":"game-scripts/prefabs/boat_rotator","title":"Boat Rotator","description":"Provides the logic and interaction handling for the Boat Rotator structure in DST, including workability, burnability, and loot dropping on destruction.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boat_rotator"},{"id":"game-scripts/prefabs/boatrace_checkpoint","title":"Boatrace Checkpoint","description":"Acts as a raceway checkpoint in the Boatrace event, detecting approaching beacons, dispensing flags, handling hammering interactions, and managing lighting and state transitions during races.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boatrace_checkpoint"},{"id":"game-scripts/prefabs/carnival_prizebooth","title":"Carnival Prizebooth","description":"A deployable carnival-themed structure that provides lighting, music effects, crafting opportunities, and loot upon destruction.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/carnival_prizebooth"},{"id":"game-scripts/prefabs/carnivalgame_common","title":"Carnivalgame Common","description":"Provides shared functionality for carnival minigame stations, including activation/deactivation lifecycle, scoring, rewards, and camera/focus management.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/carnivalgame_common"},{"id":"game-scripts/prefabs/carpentry_station","title":"Carpentry Station","description":"A multiplayer-compatible structure that enables crafting of carpentry recipes and supports blade-based upgrades; handles states including construction, usage, burning, and destruction.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/carpentry_station"},{"id":"game-scripts/prefabs/catcoonden","title":"Catcoonden","description":"Manages the lifecycle, inventory, and catcoon spawning behavior of the Catcoon Den structure in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/catcoonden"},{"id":"game-scripts/prefabs/cave_entrance","title":"Cave Entrance","description":"Manages the lifecycle and behavior of cave entrance structures, including spawning bats, handling mining to open the entrance, and state transitions based on world migration status and day/night cycles.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cave_entrance"},{"id":"game-scripts/prefabs/charlie_lecturn","title":"Charlie Lecturn","description":"Manages thelecturn\'s visual and functional state as a structure that holds a playbill stage entity and supports page-turning animations and idle behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/charlie_lecturn"},{"id":"game-scripts/prefabs/coldfirepit","title":"Coldfirepit","description":"Manages the cold fire pit structure, a weather-resistant campfire that consumes fuel at a variable rate depending on precipitation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/coldfirepit"},{"id":"game-scripts/prefabs/compostingbin","title":"Compostingbin","description":"Manages the composting process, animation states, and harvest mechanics for the Composting Bin structure, including material tracking, cycle timing, and conversion of input items into compost.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/compostingbin"},{"id":"game-scripts/prefabs/deerclops","title":"Deerclops","description":"A large, seasonal boss entity that attacks player structures and becomes aggressive when its structures-destroyed threshold is not met.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/deerclops"},{"id":"game-scripts/prefabs/deerclopseyeball_sentryward","title":"Deerclopseyeball Sentryward","description":"A deployable structure that spawns cold-ice entities, reveals map area, overrides local temperature, and emits light and effects when an eyeball is inserted.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/deerclopseyeball_sentryward"},{"id":"game-scripts/prefabs/dock_woodposts","title":"Dock Woodposts","description":"Implements dock woodpost structures and their deployable item form, handling placement, animation, loot drops on destruction, and network synchronization.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/dock_woodposts"},{"id":"game-scripts/components/dockmanager","title":"Dockmanager","description":"Manages the creation, destruction, health tracking, and structural integrity of monkey docks on Monkey Island maps.","permalink":"/dst-api-webdocs/docs/game-scripts/components/dockmanager"},{"id":"game-scripts/prefabs/dragonfly_chest","title":"Dragonfly Chest","description":"A deployable storage chest that can be upgraded to provide infinite stack size and special loot behavior upon destruction or upgrade.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/dragonfly_chest"},{"id":"game-scripts/prefabs/dustmothden","title":"Dustmothden","description":"Acts as a structure that spawns dustmoths after being repaired; manages its own durability, regenerative child-spawning, and loot drops upon destruction.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/dustmothden"},{"id":"game-scripts/prefabs/endtable","title":"Endtable","description":"A decorative and functional structure that can hold flowers and emit light, with built-in durability and destruction handling.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/endtable"},{"id":"game-scripts/prefabs/farmplot","title":"Farmplot","description":"Manages a farmplot structure that can be planted with crops and degrades when hammered or burnt, including level-specific growth rates, fertility tracking, and decorative element rendering.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/farmplot"},{"id":"game-scripts/prefabs/fence","title":"Fence","description":"Provides base prefab construction logic for walls, fences, and gates, including alignment, rotation, locking, and component setup.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/fence"},{"id":"game-scripts/prefabs/firepit","title":"Firepit","description":"A structure that provides a controllable fire source for cooking, heating, and light, fueled by consumable items and supporting charcoal production.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/firepit"},{"id":"game-scripts/prefabs/fish_box","title":"Fish Box","description":"A storage structure that preserves fish and breaks into wreckage upon hammering, releasing contents and triggering platform leaks.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/fish_box"},{"id":"game-scripts/prefabs/fossil_mound","title":"Fossil Mound","description":"Serves as an interactive structure that spawns a Stalker when fully repaired and traded with a Shadow Heart under specific conditions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/fossil_mound"},{"id":"game-scripts/prefabs/gelblob_storage","title":"Gelblob Storage","description":"Stores edible food items indefinitely by stopping their decay and preventing pick-up, and releases them with decay resumed upon taking.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/gelblob_storage"},{"id":"game-scripts/prefabs/gingerbreadhouse","title":"Gingerbreadhouse","description":"A festive structure that can be hammered to harvest loot, extinguish burning, and potentially spawn special seasonal items like gingerdead pigs.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/gingerbreadhouse"},{"id":"game-scripts/prefabs/hermithotspring","title":"Hermithotspring","description":"Manages the state, behavior, and visual synchronization of the Hermit Hot Spring structure, including heating, bathing, bathbomb effects, and construction workflow.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hermithotspring"},{"id":"game-scripts/prefabs/homesign","title":"Homesign","description":"Creates a durable, hammerable signpost that can be written on and interacts with fire and loot-dropping mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/homesign"},{"id":"game-scripts/prefabs/houndmound","title":"Houndmound","description":"A structure that spawns hounds periodically and releases them upon damage or death; it also haunts players under certain conditions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/houndmound"},{"id":"game-scripts/prefabs/icebox","title":"Icebox","description":"A storage container with refrigeration properties that accepts loot on hammering and drops its contents when destroyed.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/icebox"},{"id":"game-scripts/prefabs/kitcoonden","title":"Kitcoonden","description":"Manages a den structure that hosts hide-and-seek minigames with kitcoons, granting rewards upon successful play.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/kitcoonden"},{"id":"game-scripts/prefabs/lantern_posts","title":"Lantern Posts","description":"Generates prefabs for lantern posts, their light chains, deployment kits, and placement helpers, handling lighting, partnerships, and seasonal loot logic.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lantern_posts"},{"id":"game-scripts/prefabs/lightningrod","title":"Lightningrod","description":"Spawnable structure entity that attracts lightning strikes, stores electrical charge for up to 3 days, and can be used as a battery component by other devices.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lightningrod"},{"id":"game-scripts/prefabs/lunar_forge","title":"Lunar Forge","description":"Defines the Lunar Forge structure prefab, including prototyper, workable, and hauntable behaviors.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lunar_forge"},{"id":"game-scripts/prefabs/madscience_lab","title":"Madscience Lab","description":"Manages the mad science lab structure\'s experimental crafting workflow, including stage progression, sound, and particle effects during recipe processing.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/madscience_lab"},{"id":"game-scripts/prefabs/magician_chest","title":"Magician Chest","description":"Serves as a shadow dimension storage container for the Magician character, enabling item storage with burnable and hauntable properties.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/magician_chest"},{"id":"game-scripts/prefabs/marblepillar","title":"Marblepillar","description":"A breakable environmental object that yields marble resources when mined, with visual feedback and loot drop mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/marblepillar"},{"id":"game-scripts/prefabs/marbleshrub","title":"Marbleshrub","description":"Manages the growth, mining, and loot generation of marble shrubs, which are mutable ground structures that progress through growth stages and yield marble resources when mined.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/marbleshrub"},{"id":"game-scripts/prefabs/mast","title":"Mast","description":"Manages mast structures for boats, including sail deployment, fuel-powered lighting upgrades (lamp), lightning rod upgrades, and destruction behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mast"},{"id":"game-scripts/prefabs/mast_broken","title":"Mast Broken","description":"Represents a broken boat mast that can be repaired or burned, dropping loot and triggering visual/sound effects when interacted with.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mast_broken"},{"id":"game-scripts/prefabs/mastupgrade_lamp","title":"Mastupgrade Lamp","description":"Manages the behavior and lifecycle of a ship mast-mounted lamp, including lamp state (on/off), destruction, and loot generation upon deconstruction or burning.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mastupgrade_lamp"},{"id":"game-scripts/prefabs/mastupgrade_lightningrod","title":"Mastupgrade Lightningrod","description":"A structure component that charges upon lightning strikes and discharges at the end of each day, providing visual and functional upgrade support for masts.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mastupgrade_lightningrod"},{"id":"game-scripts/prefabs/meatrack","title":"Meatrack","description":"A structure that dries meat items when exposed to air and sunlight, and burns when ignited, destroying the dried food and producing ash instead.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/meatrack"},{"id":"game-scripts/prefabs/meatrack2","title":"Meatrack2","description":"Manages a multi-slot drying rack structure that processes raw meat and other edible items into dried versions using environmental conditions and optional salt collection.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/meatrack2"},{"id":"game-scripts/prefabs/merm_supply_structures","title":"Merm Supply Structures","description":"Creates and configures Merm structures that dispense items to Merm units after consuming stored resources.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/merm_supply_structures"},{"id":"game-scripts/prefabs/mermhouse","title":"Mermhouse","description":"A structure that spawns Merm minions during the night and regenerates them over time, with special behavior when crafted with an offering pot.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mermhouse"},{"id":"game-scripts/prefabs/mermthrone","title":"Mermthrone","description":"Represents the Merm King\u2019s throne structure in DST, supporting construction phases, occupation by the Merm King, burning, and destruction with appropriate game events and loot behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mermthrone"},{"id":"game-scripts/prefabs/mermwatchtower","title":"Mermwatchtower","description":"A structure that spawns and manages Merm guards when a Merm King is present, supporting dynamic spawning behavior and interaction with world settings and offering pots.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mermwatchtower"},{"id":"game-scripts/prefabs/mighty_gym","title":"Mighty Gym","description":"Manages the structure and behavior of the Mighty Gym, a gymnasium-style structure that allows players to gain mightiness by loading weights and working out.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mighty_gym"},{"id":"game-scripts/prefabs/molehill","title":"Molehill","description":"A structure that spawns moles underground and drops loot when dug up.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/molehill"},{"id":"game-scripts/prefabs/monkeybarrel","title":"Monkeybarrel","description":"A structure that spawns and manages monkeys, drops loot when broken, and responds to world events like acid rain and earthquakes by\u53EC\u56DE or pausing spawns.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/monkeybarrel"},{"id":"game-scripts/prefabs/moon_altar","title":"Moon Altar","description":"Manages the lifecycle, linking behavior, and crafting progression of celestial altars in the DST Moon Biome.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/moon_altar"},{"id":"game-scripts/prefabs/moonbase","title":"Moonbase","description":"Manages the Moon Base structure\'s state, including staff charging, morphing, repair, and moon-based spawner activation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/moonbase"},{"id":"game-scripts/prefabs/moondial","title":"Moondial","description":"A world-anchored structure that reflects the current moon phase visually and functionally, enabling gestalt transformation under specific moon conditions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/moondial"},{"id":"game-scripts/prefabs/mushroom_farm","title":"Mushroom Farm","description":"Manages the growth, harvesting, and state progression of a mushroom farm structure, including interactions with snow cover, spore conversion, and repair mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mushroom_farm"},{"id":"game-scripts/prefabs/mushroom_light","title":"Mushroom Light","description":"Manages the lighting, state transitions, and decay behavior of mushroom-based lanterns in DST, including battery-powered operation, spore-based colour tinting, and structural collapse when damaged.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mushroom_light"},{"id":"game-scripts/prefabs/nightlight","title":"Nightlight","description":"A deployable structure that provides shadow-light illumination and sanity benefits while consuming nightmare fuel.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/nightlight"},{"id":"game-scripts/prefabs/nightmaregrowth","title":"Nightmaregrowth","description":"A spawner-like entity that triggers the growth of a nightmare growth prefab, which emits strong negative sanity aura and can destroy nearby structures.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/nightmaregrowth"},{"id":"game-scripts/prefabs/ocean_trawler","title":"Ocean Trawler","description":"A deployable water-based fishing structure that catches and stores fish, with state-aware perish rate scaling and overflow fish release on destruction.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ocean_trawler"},{"id":"game-scripts/prefabs/oceantree_pillar","title":"Oceantree Pillar","description":"A large, water-based environmental structure that provides canopy shade, drops loot when chopped or hit, and interacts with boat collisions and lightning strikes.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceantree_pillar"},{"id":"game-scripts/prefabs/offering_pot","title":"Offering Pot","description":"Manages a structure that collects kelp to summon and hire merms, including support for upgraded variants and merm-calling mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/offering_pot"},{"id":"game-scripts/prefabs/otterden","title":"Otterden","description":"A structure that spawns and houses otters, stores loot, and reacts to player interaction or combat damage by releasing or aggroing otters.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/otterden"},{"id":"game-scripts/prefabs/pighouse","title":"Pighouse","description":"Manages a structure that spawns and shelters pigmen, with state-dependent lighting, sound, and damage behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pighouse"},{"id":"game-scripts/prefabs/pigshrine","title":"Pigshrine","description":"Manages the pig shrine structure\'s state machine, including empty, offering, burnt, and burnable states, with support for prototyping, trading, and salvage behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pigshrine"},{"id":"game-scripts/prefabs/pigtorch","title":"Pigtorch","description":"A structure that produces guards and burns fuel over time, extinguishing when its fuel runs out or during rain.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pigtorch"},{"id":"game-scripts/prefabs/pirate_flag_pole","title":"Pirate Flag Pole","description":"Implements the pirate flag pole structure, managing its visual animation, burnable behavior, loot drops, and flag number assignment.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pirate_flag_pole"},{"id":"game-scripts/prefabs/portableblender","title":"Portableblender","description":"Manages the behavior and state of the portable blender structure and its deployed item form, including cooking functionality, burn mechanics, and workable construction.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/portableblender"},{"id":"game-scripts/prefabs/portablespicer","title":"Portablespicer","description":"Manages the logic for a portable cooking device that can be deployed, used to cook stews, and transitions to an item form when dismantled or destroyed.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/portablespicer"},{"id":"game-scripts/components/portablestructure","title":"Portablestructure","description":"Provides a callback mechanism for custom dismantling logic when a portable structure is disassembled.","permalink":"/dst-api-webdocs/docs/game-scripts/components/portablestructure"},{"id":"game-scripts/prefabs/punchingbag","title":"Punchingbag","description":"A deployable, hammerable structure that absorbs and displays hit damage via rotating numeric digits; accepts equipped items via trader logic and drops loot when destroyed.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/punchingbag"},{"id":"game-scripts/prefabs/quagmire_crates","title":"Quagmire Crates","description":"Factory function for generating Quagmire crate prefabs, supporting both empty crates and pre-filled kits (e.g., oven, grill).","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_crates"},{"id":"game-scripts/prefabs/quagmire_mealingstone","title":"Quagmire Mealingstone","description":"A craftable structure prefab used in the Quagmire DLC that enables storage of ground ingredients and acts as a crafting node for Quagmire-specific recipes.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_mealingstone"},{"id":"game-scripts/prefabs/quagmire_mushroomstump","title":"Quagmire Mushroomstump","description":"A static, passive quagmire world structure that serves as a visual and thematic landmark in the Quagmire biome, with no gameplay functionality beyond appearance and identification.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_mushroomstump"},{"id":"game-scripts/prefabs/quagmire_safe","title":"Quagmire Safe","description":"A locked storage container used in the Quagmire biome, requiring a key to open.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_safe"},{"id":"game-scripts/prefabs/quagmire_swampig_house","title":"Quagmire Swampig House","description":"Creates the visual and physical representation of a Quagmire swamp pig house, including normal and rubble states with appropriate animations and physics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_swampig_house"},{"id":"game-scripts/prefabs/rainometer","title":"Rainometer","description":"A structure component that tracks local rain levels via animation and responds to player interaction and environmental effects like fire.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rainometer"},{"id":"game-scripts/prefabs/resurrectionstatue","title":"Resurrectionstatue","description":"Manages the resurrection statue entity, allowing players to attune it to\u590D\u6D3B dead players in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/resurrectionstatue"},{"id":"game-scripts/prefabs/rock_light","title":"Rock Light","description":"A durable, fueled light source that transitions between burn states based on fuel level and can trigger a controlled explosion when fully depleted.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rock_light"},{"id":"game-scripts/prefabs/saltbox","title":"Saltbox","description":"A storage container that preserves perishable items at a fixed rate and can be destroyed via hammering to release its contents.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/saltbox"},{"id":"game-scripts/prefabs/saltlick","title":"Saltlick","description":"A durable structure that provides salt-based sustenance for creatures and players over time, supporting improved construction and repair mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/saltlick"},{"id":"game-scripts/prefabs/scarecrow","title":"Scarecrow","description":"A decorative and functional structure that can be built by players to occupy space and interact with dressing-up mechanics; it supports hammering, burning, and skin changes.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/scarecrow"},{"id":"game-scripts/prefabs/scienceprototyper","title":"Scienceprototyper","description":"Creates and configures the science and alchemy prototype machines, including their prototyping trees, animations, interactions, and seasonal gift mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/scienceprototyper"},{"id":"game-scripts/prefabs/seafaring_prototyper","title":"Seafaring Prototyper","description":"A deployable structure that provides prototyping capabilities for the Seafaring content, with workable and burnable behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/seafaring_prototyper"},{"id":"game-scripts/prefabs/sentryward","title":"Sentryward","description":"A deployable map-revealing structure that provides illumination and reveals fog of war; it can be hammered to collect loot and deactivates when burnt.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/sentryward"},{"id":"game-scripts/stategraphs/SGfiresuppressor","title":"Sgfiresuppressor","description":"Manages the state machine for the Fire Suppressor structure, handling its startup, idle, spinning, and extinguishing animations and sounds.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGfiresuppressor"},{"id":"game-scripts/stategraphs/SGmoondial","title":"Sgmoondial","description":"Manages the state machine and animation/sound behavior for the Moon Dial structure in DST, including phase transitions, glassing effects, and crafting interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGmoondial"},{"id":"game-scripts/stategraphs/SGwinona_catapult","title":"Sgwinona Catapult","description":"Manages the animation, power state, and attack logic for Winona\'s catapult structure, including projectile launching and elemental battery consumption.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGwinona_catapult"},{"id":"game-scripts/prefabs/shadow_forge","title":"Shadow Forge","description":"A structure component that functions as a prototype device for crafting shadow-based recipes, supporting activation, work interactions via hammering, and loot dropping upon destruction.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shadow_forge"},{"id":"game-scripts/prefabs/sharkboi_icespike","title":"Sharkboi Icespike","description":"A deployable frozen ground spike that damages nearby entities, breaks collapsible workable structures, and can be mined for ice resources.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/sharkboi_icespike"},{"id":"game-scripts/prefabs/shellweaver","title":"Shellweaver","description":"A science station that requires heat and proximity to function, unlocks craftable recipes via prototyping, and upgrades its tech tree based on pearl decoration score.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shellweaver"},{"id":"game-scripts/prefabs/sisturn","title":"Sisturn","description":"A decorative and functional structure that accepts flower-type items, modifies perish rates and sanity aura based on item content and player skill tree upgrades, and triggers special effects during moon blossoms.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/sisturn"},{"id":"game-scripts/prefabs/slurtlehole","title":"Slurtlehole","description":"A hostile, structure-like entity that spawns slurtles or snurtles over time and explodes when ignited or destroyed.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/slurtlehole"},{"id":"game-scripts/prefabs/statueharp","title":"Statueharp","description":"A breakable decorative statue that drops marble loot when mined and supports dynamic animation states and Charlie-induced modifications.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/statueharp"},{"id":"game-scripts/prefabs/steeringwheel","title":"Steeringwheel","description":"Manages the logic for a boat\'s steering wheel, including player interaction, burning effects, and looting upon destruction.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/steeringwheel"},{"id":"game-scripts/prefabs/stickheads","title":"Stickheads","description":"Creates and configures the Pig Head and Merm Head prefabs, which are destructible structures that produce specific loot, respond to fire, wake up on full moons, and can be haunted.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/stickheads"},{"id":"game-scripts/prefabs/table_winters_feast","title":"Table Winters Feast","description":"Manages festive table functionality including food\u653E\u7F6E, seasonal feast registration, lighting effects, and interaction with the Winters Feast event system.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/table_winters_feast"},{"id":"game-scripts/prefabs/tacklestation","title":"Tacklestation","description":"A crafting station prefab that enables players to learn and prototype fishing-related blueprints; it supports state persistence, burning, haunting, and loot generation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/tacklestation"},{"id":"game-scripts/prefabs/telebase","title":"Telebase","description":"Manages a structure that accepts gem placements to enable teleportation functionality, and responds to hammering by destroying itself and dropping gems.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/telebase"},{"id":"game-scripts/prefabs/tent","title":"Tent","description":"Manages the behavior and state of sleeping structures (tent and siestahut), handling use tracking, sleep interactions, burning, and dismantling.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/tent"},{"id":"game-scripts/prefabs/townportal","title":"Townportal","description":"Manages the town portal structure, including channeling activation, inter-portal linking, teleportation, and dismantling behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/townportal"},{"id":"game-scripts/prefabs/trophyscale_fish","title":"Trophyscale Fish","description":"A weighable fish stand that holds and displays caught trophy fish, supports building/removal via actions, and handles item persistence across reloads and burn states.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/trophyscale_fish"},{"id":"game-scripts/prefabs/trophyscale_oversizedveggies","title":"Trophyscale Oversizedveggies","description":"A weight-based trophy structure that accepts oversized vegetables and displays their weight and harvest day using animated digit symbols.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/trophyscale_oversizedveggies"},{"id":"game-scripts/prefabs/vault_furniture","title":"Vault Furniture","description":"Defines two prefabs (vault_table_round and vault_stool) with variation management, decoration handling, and sittable/inspectable behavior for DST vault environments.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/vault_furniture"},{"id":"game-scripts/prefabs/vault_rune","title":"Vault Rune","description":"Represents an interactive ancient rune stone used for lore display in the Vault biome.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/vault_rune"},{"id":"game-scripts/prefabs/vault_statues","title":"Vault Statues","description":"Manages visual and narrative state for vault-themed statues, including scene-specific animation and lore display in scrapbook mode.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/vault_statues"},{"id":"game-scripts/prefabs/wagstaff_machinery","title":"Wagstaff Machinery","description":"Handles the creation, rendering, and destruction logic for the Wagstaff machinery structure, including dynamic debris animation, loot generation, and event signaling.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wagstaff_machinery"},{"id":"game-scripts/prefabs/wardrobe","title":"Wardrobe","description":"A placeable structure component that allows players to store and manage items via an inventory interface, while supporting interaction callbacks, hammering, burning, and save/load persistence.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wardrobe"},{"id":"game-scripts/prefabs/wargshrine","title":"Wargshrine","description":"A structure that accepts torches to become active, enabling a prototyper and emitting flame; deactivates when extinguished or deconstructed.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wargshrine"},{"id":"game-scripts/prefabs/wasphive","title":"Wasphive","description":"A hive-like structure that periodically spawns killer bees and reacts to nearby players and attacks by releasing aggressive wasps.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wasphive"},{"id":"game-scripts/map/static_layouts/wasphive_grass_easy","title":"Wasphive Grass Easy","description":"Static map layout for the wasphive biome with easy difficulty grass placement and wasphive structures.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/wasphive_grass_easy"},{"id":"game-scripts/prefabs/waterpump","title":"Waterpump","description":"A functional entity that channels water in a circular area, launching water projectiles when used; breaks upon being hammered and extinguishes flames.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/waterpump"},{"id":"game-scripts/prefabs/watertree_pillar","title":"Watertree Pillar","description":"Acts as a large ocean-dwelling structure that periodically spawns grassgators, drops items when rammed by boats, blocks lightning, and manages canopy effects for nearby players.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/watertree_pillar"},{"id":"game-scripts/prefabs/wendy_resurrectiongrave","title":"Wendy Resurrectiongrave","description":"Manages a special resurrection altar for Wendy that allows linking to a player and consuming health to enable resurrection of fallen allies.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wendy_resurrectiongrave"},{"id":"game-scripts/prefabs/winch","title":"Winch","description":"Manages the mechanical winch structure that can lower and raise a claw to salvage submerged objects, while interacting with boat physics and inventory systems.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/winch"},{"id":"game-scripts/prefabs/winona_battery_high","title":"Winona Battery High","description":"Defines the Winona Battery High structure and item prefab for power generation and circuit management.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/winona_battery_high"},{"id":"game-scripts/prefabs/winter_treestand","title":"Winter Treestand","description":"A structure that can be planted with a winter tree seed to grow into a full winter tree and yields wood when harvested before full growth.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/winter_treestand"},{"id":"game-scripts/prefabs/winterometer","title":"Winterometer","description":"Displays and tracks the current ambient temperature using a meter animation, updating once per second and reacting to burning or hammering.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/winterometer"},{"id":"game-scripts/prefabs/wintersfeastoven","title":"Wintersfeastoven","description":"Implements the Winters Feast Oven, a multi-stage cooking station that requires science-based cooking steps and produces festive dishes.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wintersfeastoven"},{"id":"game-scripts/prefabs/wobster_den","title":"Wobster Den","description":"A water-based structure that spawns and regenerates Wobster creatures over time, interacts with player mining actions and boat collisions, and can transform into a Moonglass Wobster Den during Halloween events.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wobster_den"},{"id":"game-scripts/prefabs/wormhole","title":"Wormhole","description":"Manages the Wormhole prefab, a teleportation structure that opens when players approach and teleports entities (including followers) to a linked Teleporter.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wormhole"},{"id":"game-scripts/prefabs/wx78_drone_delivery","title":"Wx78 Drone Delivery","description":"Spawnable delivery drone structure for WX-78 that transports items between map locations, with flying animations, shadow effects, and skill-gated usage.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wx78_drone_delivery"},{"id":"game-scripts/prefabs/yot_catcoonshrine","title":"Yot Catcoonshrine","description":"Acts as a special\u796D\u575B that holds a birdfeather offering and becomes a prototyper once activated; supports burning, hammering, and state persistence.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yot_catcoonshrine"},{"id":"game-scripts/prefabs/yotb_beefaloshrine","title":"Yotb Beefaloshrine","description":"Manages the interactive shrine structure for the Yotb mod, handling offering placement, trading, burning state, and dynamic prize changes during contests.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yotb_beefaloshrine"},{"id":"game-scripts/prefabs/yotb_post","title":"Yotb Post","description":"Manages the behavior and state of the yotb_post structure, including hammering, hitching, marking, burning, and ribbon animation effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yotb_post"},{"id":"game-scripts/prefabs/yotb_sewingmachine","title":"Yotb Sewingmachine","description":"Provides a structure-based crafting interface for beefalo sewing recipes, managing sewing state, animations, sound, and interaction callbacks.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yotb_sewingmachine"},{"id":"game-scripts/prefabs/yotb_stage","title":"Yotb Stage","description":"Manages the stage booth structure, handling placement, interaction (hammering, hitting), voice playback, and cleanup with event notifications and loot drops.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yotb_stage"},{"id":"game-scripts/prefabs/yotc_carrat_race_start","title":"Yotc Carrat Race Start","description":"A structure that initiates and manages carrat racing events; it spawns racers, triggers race start/end logic, and handles destruction with burn and hammer interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yotc_carrat_race_start"},{"id":"game-scripts/prefabs/yotc_carrat_scale","title":"Yotc Carrat Scale","description":"A gym-scale structure that accepts carrat rats, displays their stats via animated rods, and manages their interaction during training.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yotc_carrat_scale"},{"id":"game-scripts/prefabs/yotc_carratshrine","title":"Yotc Carratshrine","description":"Manages the Carrat Shrine entity\'s state transitions, offering interactions, prototyping access, and burn mechanics in the YOTC content.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yotc_carratshrine"},{"id":"game-scripts/prefabs/yotd_dragonshrine","title":"Yotd Dragonshrine","description":"A ritual shrine that accepts charcoal offerings, activates a prototyper when offered, and resets to an empty trader state when used or extinguished.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yotd_dragonshrine"},{"id":"game-scripts/prefabs/yoth_knightshrine","title":"Yoth Knightshrine","description":"Manages the lifecycle, offering acceptance, and heckler behavior of the Yoth Knightshrine structure in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yoth_knightshrine"},{"id":"game-scripts/prefabs/yotr_decor","title":"Yotr Decor","description":"Creates decorative campfire-like structures that burn fuel, produce light, and interact with weather and gameplay events.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yotr_decor"},{"id":"game-scripts/prefabs/yotr_rabbitshrine","title":"Yotr Rabbitshrine","description":"A seasonal event structure that spawns cooperative bunnymen, accepts offerings of carrots to unlock crafting options, and triggers special gameplay during the YOTR event.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yotr_rabbitshrine"},{"id":"game-scripts/prefabs/yots_snakeshrine","title":"Yots Snakeshrine","description":"A boss-adjacent structure that accepts monster meat offerings, unlocks crafting capabilities when offered, and can be hammered down for rewards.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yots_snakeshrine"}],"unlisted":false}}')}}]);